import { _decorator, Component, director, Node, Label, Button, ProgressBar } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('TowerScene')
export class TowerScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    challengeBtn: Button = null;
    
    @property(Button)
    sweepBtn: Button = null;
    
    @property(Label)
    currentFloorLabel: Label = null;
    
    @property(Label)
    maxFloorLabel: Label = null;
    
    @property(Label)
    rewardLabel: Label = null;
    
    @property(Label)
    enemyInfoLabel: Label = null;
    
    @property(ProgressBar)
    difficultyBar: ProgressBar = null;
    
    private currentFloor = 1;
    private maxClearedFloor = 1;
    private maxFloors = 100;
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.challengeBtn.node.on(Button.EventType.CLICK, this.onChallenge, this);
        this.sweepBtn.node.on(Button.EventType.CLICK, this.onSweep, this);
    }
    
    start() {
        this.updateUI();
    }
    
    updateUI() {
        this.currentFloorLabel.string = `当前层数: ${this.currentFloor}`;
        this.maxFloorLabel.string = `最高通关: ${this.maxClearedFloor}层`;
        
        // 计算敌人强度
        const enemyLevel = 50 + this.currentFloor * 2;
        const enemyHp = 1000 + this.currentFloor * 500;
        const enemyAttack = 100 + this.currentFloor * 10;
        
        this.enemyInfoLabel.string = `敌人: Lv.${enemyLevel}\n血量: ${enemyHp}\n攻击: ${enemyAttack}`;
        
        // 难度条
        this.difficultyBar.progress = this.currentFloor / this.maxFloors;
        
        // 奖励预览
        const expReward = this.currentFloor * 1000;
        const goldReward = this.currentFloor * 500;
        this.rewardLabel.string = `通关奖励:\n${expReward}经验\n${goldReward}香火钱`;
        
        // 扫荡按钮只在已通关层可用
        this.sweepBtn.interactable = this.currentFloor <= this.maxClearedFloor;
    }
    
    onChallenge() {
        // 模拟战斗
        const playerLevel = GameManager.getInstance().playerData.getLevel();
        const enemyLevel = 50 + this.currentFloor * 2;
        
        // 胜负判定（简化）
        const winChance = Math.min(0.9, Math.max(0.1, (playerLevel - enemyLevel + 50) / 100));
        const win = Math.random() < winChance;
        
        if (win) {
            // 胜利
            const expReward = this.currentFloor * 1000;
            const goldReward = this.currentFloor * 500;
            
            GameManager.getInstance().playerData.addCurrency('incense_money', goldReward);
            
            alert(`挑战成功！获得${expReward}经验和${goldReward}香火钱`);
            
            if (this.currentFloor > this.maxClearedFloor) {
                this.maxClearedFloor = this.currentFloor;
            }
            
            this.currentFloor++;
            if (this.currentFloor > this.maxFloors) {
                alert('恭喜通关100层！');
                this.currentFloor = this.maxFloors;
            }
        } else {
            // 失败
            alert('挑战失败，请提升实力后再来');
        }
        
        this.updateUI();
    }
    
    onSweep() {
        if (this.currentFloor > this.maxClearedFloor) {
            alert('未通关该层，无法扫荡');
            return;
        }
        
        // 扫荡获得80%奖励
        const expReward = Math.floor(this.currentFloor * 1000 * 0.8);
        const goldReward = Math.floor(this.currentFloor * 500 * 0.8);
        
        GameManager.getInstance().playerData.addCurrency('incense_money', goldReward);
        
        alert(`扫荡成功！获得${expReward}经验和${goldReward}香火钱`);
        
        this.currentFloor++;
        this.updateUI();
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
